"use client";

import { useState, useEffect } from "react";
import KakaoMap from "@/components/map/KakaoMap"; 
import "./pharmacy.css";

// 프론트엔드에서 사용할 데이터 타입 (UI 편의성을 위해 기존 구조 유지)
interface Place {
  id: string;
  place_name: string;      // 백엔드: placeName
  category_name: string;   
  phone: string;
  address_name: string;    // 백엔드: addressName
  road_address_name: string; // 백엔드: roadAddressName
  x: string;
  y: string;
  place_url: string;       // 백엔드: placeUrl
  distance?: string;
  QT?: string;             // 백엔드: qt (진료시간/영업시간)
}

export default function PharmacyPage() {
  const [pharmacies, setPharmacies] = useState<Place[]>([]);
  const [isLoading, setIsLoading] = useState(true);

  // 페이지네이션 상태
  const [currentPage, setCurrentPage] = useState(1);
  const itemsPerPage = 6; // 한 페이지당 카드 수

  // 1. 컴포넌트 마운트 시 백엔드 DB에서 데이터 조회
  useEffect(() => {
    const fetchPharmacies = async () => {
      try {
        setIsLoading(true);
        // 백엔드 API 호출 (포트 번호나 경로는 환경에 맞게 수정 필요)
        const response = await fetch("http://localhost:8080/api/night");
        
        if (!response.ok) {
          throw new Error("데이터를 불러오는데 실패했습니다.");
        }

        const data = await response.json();

        // 2. 백엔드 데이터(CamelCase) -> 프론트엔드 데이터(SnakeCase) 매핑
        // 백엔드 Entity 필드명과 프론트엔드 사용 필드명을 맞춰주는 작업입니다.
        const mappedData: Place[] = data.map((item: any) => ({
          id: item.id.toString(),
          place_name: item.placeName,
          category_name: "의료,건강 > 약국", // DB에 없으면 기본값 혹은 추가 저장 필요
          phone: item.phone,
          address_name: item.addressName,
          road_address_name: item.roadAddressName,
          x: item.x,
          y: item.y,
          place_url: item.placeUrl,
          QT: item.qt || "", // DB에 qt 컬럼이 null일 경우 대비
          distance: "", // DB 데이터는 거리 계산 로직이 없으면 비워둠 (필요 시 Haversine 공식 등으로 계산)
        }));

        setPharmacies(mappedData);
      } catch (error) {
        console.error("약국 정보 로딩 실패:", error);
        alert("약국 정보를 불러올 수 없습니다. 관리자에게 문의하세요.");
      } finally {
        setIsLoading(false);
      }
    };

    fetchPharmacies();
  }, []);

  // 현재 페이지 데이터 계산
  const indexOfLastItem = currentPage * itemsPerPage;
  const indexOfFirstItem = indexOfLastItem - itemsPerPage;
  const currentItems = pharmacies.slice(indexOfFirstItem, indexOfLastItem);
  const totalPages = Math.ceil(pharmacies.length / itemsPerPage);

  // 페이지 변경 핸들러
  const handlePageChange = (pageNumber: number) => {
    setCurrentPage(pageNumber);
    document.querySelector(".pharmacy-list-section")?.scrollIntoView({ behavior: "smooth" });
  };

  return (
    <div className="pharmacy-container">
      {/* 헤더 영역 */}
      <div className="pharmacy-header">
        <h1 className="pharmacy-title">주변 약국 찾기 🏥</h1>
        <p className="pharmacy-desc">
          저장된 약국 데이터를 조회합니다. <strong>[관리자 동기화]</strong>가 최신 상태인지 확인하세요.
        </p>
      </div>

      {/* 지도 영역 */}
      {/* 이제 지도는 데이터를 받아와서 마커를 찍어주는 역할(Display)만 수행한다고 가정 */}
      <div className="map-section">
        <KakaoMap pharmacies={pharmacies} /> 
      </div>

      {/* 결과 리스트 영역 */}
      <div className="pharmacy-list-section">
        <div className="list-header">
          <h3>
            약국 목록 <span className="count">{pharmacies.length}</span>건
          </h3>
          <span className="page-info">
             (현재 {currentPage} / {totalPages || 1} 페이지)
          </span>
        </div>

        {isLoading ? (
          <div className="loading-msg">
            <div className="spinner"></div>
            약국 정보를 DB에서 불러오는 중입니다...
          </div>
        ) : pharmacies.length > 0 ? (
          <>
            <div className="pharmacy-grid">
              {currentItems.map((place) => (
                <div 
                  key={place.id} 
                  className="pharmacy-card"
                  onClick={() => window.open(place.place_url, "_blank")}
                  title="클릭하여 상세 정보 보기"
                >
                  <div className="card-header">
                    <span className="badge-category">약국</span>
                    {place.distance && place.distance !== "0" && (
                      <span className="badge-distance">{place.distance}m</span>
                    )}
                  </div>
                  
                  <div className="card-body">
                    <h4 className="place-name">{place.place_name}</h4>
                    <p className="category-path">
                      {place.category_name.includes(">") 
                        ? place.category_name.split(">").pop()?.trim() 
                        : place.category_name}
                    </p>
                    
                    {/* ✅ QT (진료시간) 표시 영역 */}
                    {place.QT && (
                      <div className="info-row qt-row">
                        <span className="label">🕒 시간</span>
                        <span className="value qt-value">{place.QT}</span>
                      </div>
                    )}

                    <div className="info-row">
                      <span className="label">도로명</span>
                      <span className="value">{place.road_address_name || "정보 없음"}</span>
                    </div>
                    <div className="info-row sub-addr">
                      <span className="label">지번</span>
                      <span className="value">{place.address_name}</span>
                    </div>
                    <div className="info-row phone-row">
                      <span className="label">전화</span>
                      <span className="value phone">{place.phone || "번호 없음"}</span>
                    </div>
                  </div>

                  <div className="card-footer">
                    <a
                      href={`https://map.kakao.com/link/to/${place.place_name},${place.y},${place.x}`}
                      target="_blank"
                      rel="noopener noreferrer"
                      className="btn-path"
                      onClick={(e) => e.stopPropagation()} 
                    >
                      📍 길찾기
                    </a>
                    <a
                      href={place.place_url}
                      target="_blank"
                      rel="noopener noreferrer"
                      className="btn-detail"
                      onClick={(e) => e.stopPropagation()}
                    >
                      상세보기 ↗
                    </a>
                  </div>
                </div>
              ))}
            </div>

            {/* 페이지네이션 컨트롤 */}
            <div className="pagination">
              <button 
                onClick={() => handlePageChange(currentPage - 1)} 
                disabled={currentPage === 1}
                className="page-btn prev"
              >
                이전
              </button>
              
              {Array.from({ length: totalPages }, (_, i) => i + 1).map((number) => (
                <button
                  key={number}
                  onClick={() => handlePageChange(number)}
                  className={`page-num ${currentPage === number ? "active" : ""}`}
                >
                  {number}
                </button>
              ))}

              <button 
                onClick={() => handlePageChange(currentPage + 1)} 
                disabled={currentPage === totalPages}
                className="page-btn next"
              >
                다음
              </button>
            </div>
          </>
        ) : (
          <div className="empty-msg">
            <p>
              저장된 약국 데이터가 없습니다. 😭<br />
              관리자 페이지에서 <strong>데이터 동기화</strong>를 진행해주세요.
            </p>
          </div>
        )}
      </div>
    </div>
  );
}